/**
 * ContextProcessor
 * Handles @Context annotations for global context binding.
 */
module.exports = {
  processScan(meta, ctx) {},

  processInstantiate(meta, ctx) {},

  processDI(meta, ctx) {},

  /**
   * Binds the class instance to the context during the Init stage.
   */
  processInit(meta, ctx) {
    ctx.context[meta.className] = new meta.classRef();
    ctx.log.push(`@Context bound: ${meta.className}`);
  },

  processRun(meta, ctx) {}
};